#include<bits/stdc++.h>
#define ull unsigned long long
using namespace std;
inline ull read(){
    ull x=0,f=1;
    char ch=getchar();
    while(ch<'0'||ch>'9'){if(ch=='-')f=-1;ch=getchar();}
    while(ch>='0'&&ch<='9')x=x*10+ch-'0',ch=getchar();
    return x*f;
}
const ull N=4e6+5;
ull n,m,ans;
vector<ull> a[N];
int main(void){
	n=read(),m=read();
	for(ull i=1,s;i<=n;i++){
		s=read();
		for(ull j=1,w;j<=s;j++)w=read(),a[i].push_back(w);
	}
	for(ull i=1,x,y;i<=m;i++)x=read(),y=read(),ans^=a[x][y-1];
	cout<<ans;
	return false;
}
